package com.example.sociallogin

import android.app.Activity
import android.content.Intent
import android.os.Bundle
import android.util.Log
import android.widget.Button
import android.widget.LinearLayout
import androidx.appcompat.app.AppCompatActivity
import com.facebook.CallbackManager
import com.facebook.FacebookCallback
import com.facebook.FacebookException
import com.facebook.FacebookSdk
import com.facebook.login.LoginManager
import com.facebook.login.LoginResult
import com.google.android.gms.auth.api.signin.GoogleSignIn
import com.google.android.gms.auth.api.signin.GoogleSignInAccount
import com.google.android.gms.auth.api.signin.GoogleSignInClient
import com.google.android.gms.auth.api.signin.GoogleSignInOptions
import com.google.android.gms.common.api.ApiException

class SocialLoginActivity : AppCompatActivity() {

    companion object {
        // Facebook credentials
        private const val FACEBOOK_APP_ID = "123456789012345"
        private const val FACEBOOK_APP_SECRET = "abcdef1234567890abcdef1234567890"
        // Google credentials
        private const val GOOGLE_CLIENT_ID = "1234-abcdef.apps.googleusercontent.com"
        private const val GOOGLE_CLIENT_SECRET = "GOCSpx-AbCdEf123456"
        private const val RC_SIGN_IN = 9001
    }

    private lateinit var callbackManager: CallbackManager
    private lateinit var googleSignInClient: GoogleSignInClient

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        // Initialize Facebook SDK
        FacebookSdk.setApplicationId(FACEBOOK_APP_ID)
        FacebookSdk.sdkInitialize(applicationContext)

        // Setup layout programmatically
        val layout = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(50, 50, 50, 50)
        }

        // Facebook Login Button
        val fbLoginButton = Button(this).apply {
            text = "Login with Facebook"
        }
        layout.addView(fbLoginButton)

        // Google Login Button
        val googleLoginButton = Button(this).apply {
            text = "Login with Google"
        }
        layout.addView(googleLoginButton)

        setContentView(layout)

        // Setup Facebook Callback Manager
        callbackManager = CallbackManager.Factory.create()

        fbLoginButton.setOnClickListener {
            LoginManager.getInstance().logInWithReadPermissions(this, listOf("email", "public_profile"))
            LoginManager.getInstance().registerCallback(callbackManager, object : FacebookCallback<LoginResult> {
                override fun onSuccess(result: LoginResult?) {
                    Log.d("SocialLogin", "Facebook login success: ${result?.accessToken?.token}")
                    // Further processing with access token if needed.
                }

                override fun onCancel() {
                    Log.d("SocialLogin", "Facebook login cancelled.")
                }

                override fun onError(error: FacebookException?) {
                    Log.e("SocialLogin", "Facebook login error: ${error?.message}")
                }
            })
        }

        // Setup Google Sign-In Options
        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
            // Using the provided client id; note that normally you'd use requestServerAuthCode or requestIdToken.
            .requestIdToken(GOOGLE_CLIENT_ID)
            .requestEmail()
            .build()
        googleSignInClient = GoogleSignIn.getClient(this, gso)

        googleLoginButton.setOnClickListener {
            val signInIntent = googleSignInClient.signInIntent
            startActivityForResult(signInIntent, RC_SIGN_IN)
        }
    }

    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        callbackManager.onActivityResult(requestCode, resultCode, data)
        super.onActivityResult(requestCode, resultCode, data)

        if (requestCode == RC_SIGN_IN) {
            try {
                val task = GoogleSignIn.getSignedInAccountFromIntent(data)
                val account: GoogleSignInAccount? = task.getResult(ApiException::class.java)
                Log.d("SocialLogin", "Google sign in success: ${account?.email}")
                // Further processing with account if needed.
            } catch (e: ApiException) {
                Log.e("SocialLogin", "Google sign in failed, code: ${e.statusCode}, message: ${e.message}")
            }
        }
    }
